func selectedMutableFields(flags []string) ([]string, error) {
	keys := splitCSVFlags(flags)
	if len(keys) == 0 {
		keys = []string{"auction", "images", "notes", "population", "price-guide"}
	}
	seen := map[string]struct{}{}
	var fields []string
	for _, key := range keys {
		names, ok := mutableFieldMap[key]
		if !ok {
			return nil, fmt.Errorf("invalid --field %q", key)
		}
		for _, name := range names {
			if _, ok := seen[name]; !ok {
				seen[name] = struct{}{}
				fields = append(fields, name)
			}
		}
	}
	return fields, nil
}

func refreshTargetCerts(s *store.Store, all bool, certFlags []string, older string) ([]string, error) {
	if len(certFlags) > 0 {
		raw := splitCSVFlags(certFlags)
		normalized := make([]string, 0, len(raw))
		for _, r := range raw {
			cert, _, err := normalizeCertNo(r)
			if err != nil {
				return nil, usageErr(fmt.Errorf("--cert %q: %w", r, err))
			}
			normalized = append(normalized, cert)
		}
		return normalized, nil
	}
	if !all {
		return nil, nil
	}
	if strings.TrimSpace(older) == "" {
		return s.ListIDs("coin")
	}
	d, err := parseRefreshDuration(older)
	if err != nil {
		return nil, usageErr(err)
	}
	cutoff := time.Now().UTC().Add(-d).Format("2006-01-02 15:04:05")
	rows, err := s.DB().Query(`SELECT id FROM resources WHERE resource_type='coin' AND datetime(updated_at) < datetime(?)`, cutoff)
	if err != nil {
		return nil, fmt.Errorf("query older coins: %w", err)
	}
	defer rows.Close()
	var ids []string
	for rows.Next() {
		var id string
		if err := rows.Scan(&id); err != nil {
			return nil, fmt.Errorf("scan older coin id: %w", err)
		}
		ids = append(ids, id)
	}
	return ids, rows.Err()
}

func parseRefreshDuration(raw string) (time.Duration, error) {
	s := strings.TrimSpace(strings.ToLower(raw))
	if strings.HasSuffix(s, "d") {
		n, err := strconv.Atoi(strings.TrimSuffix(s, "d"))
		if err != nil {
			return 0, fmt.Errorf("invalid duration %q", raw)
		}
		return time.Duration(n) * 24 * time.Hour, nil
	}
	if d, err := time.ParseDuration(s); err == nil {
		return d, nil
	}
	n, err := strconv.Atoi(s)
	if err != nil {
		return 0, fmt.Errorf("invalid duration %q", raw)
	}
	return time.Duration(n) * time.Second, nil
}

func mergeMutableFields(oldRaw, newRaw json.RawMessage, fields []string) (json.RawMessage, []refreshDiff, error) {
	var oldObj, newObj map[string]any
	if err := json.Unmarshal(oldRaw, &oldObj); err != nil {
		return nil, nil, fmt.Errorf("parse cached coin: %w", err)
	}
	if err := json.Unmarshal(newRaw, &newObj); err != nil {
		return nil, nil, fmt.Errorf("parse refreshed coin: %w", err)
	}
	var diffs []refreshDiff
	for _, name := range fields {
		oldVal, oldOK := oldObj[name]
		newVal, newOK := newObj[name]
		if !newOK {
			continue
		}
		if !oldOK || !reflect.DeepEqual(oldVal, newVal) {
			diffs = append(diffs, refreshDiff{Name: name, Old: oldVal, New: newVal})
			oldObj[name] = newVal
		}
	}
	merged, err := json.Marshal(oldObj)
	if err != nil {
		return nil, nil, fmt.Errorf("marshal merged coin: %w", err)
	}
	return merged, diffs, nil
}

func splitCSVFlags(values []string) []string {
	seen := map[string]struct{}{}
	var out []string
	for _, v := range values {
		for _, part := range strings.Split(v, ",") {
			part = strings.TrimSpace(part)
			if part == "" {
				continue
			}
			if _, ok := seen[part]; ok {
				continue
			}
			seen[part] = struct{}{}
			out = append(out, part)
		}
	}
	return out
}
